const body = $json.body ?? $json;
const event =
  body.event ||
  body.type ||
  body.eventName ||
  body.trigger ||
  body.data?.event ||
  'UNKNOWN';

const payload = body.data ?? body.payload ?? body;

const key = payload.key || payload.messageKey || {};
const message = payload.message || payload.data?.message || {};
const groupJid =
  key.remoteJid ||
  payload.remoteJid ||
  payload.chatId ||
  payload.groupJid ||
  payload.id ||
  null;

const senderJid =
  key.participant ||
  payload.participant ||
  payload.sender ||
  payload.senderJid ||
  payload.key?.participant ||
  null;

const participantsChanged =
  payload.participants ||
  payload.users ||
  payload.actionParticipants ||
  [];

function extractText(msg) {
  if (!msg) return '';
  if (typeof msg.conversation === 'string') return msg.conversation;
  if (msg.extendedTextMessage?.text) return msg.extendedTextMessage.text;
  if (msg.imageMessage?.caption) return msg.imageMessage.caption;
  if (msg.videoMessage?.caption) return msg.videoMessage.caption;
  if (msg.buttonsResponseMessage?.selectedDisplayText) return msg.buttonsResponseMessage.selectedDisplayText;
  if (msg.listResponseMessage?.title) return msg.listResponseMessage.title;
  if (msg.templateButtonReplyMessage?.selectedDisplayText) return msg.templateButtonReplyMessage.selectedDisplayText;
  return '';
}

const messageText = extractText(message);
const isGroup = !!groupJid && String(groupJid).endsWith('@g.us');

function normalizePhone(value) {
  if (!value) return null;
  return String(value).replace(/[^0-9]/g, '');
}

return [{
  json: {
    receivedAt: new Date().toISOString(),
    event,
    raw: body,
    payload,
    key,
    message,
    messageId: key.id || payload.id || null,
    groupJid,
    senderJid,
    senderPhone: normalizePhone(senderJid),
    remotePhone: normalizePhone(groupJid),
    messageText,
    fromMe: !!key.fromMe || !!payload.fromMe,
    isGroup,
    participantAction: payload.action || payload.operation || null,
    participantsChanged,
  }
}];

const ev = $('Normalize Event').first().json || {};
const membersResp = $json.membersResp || {};
const policyResp = $json.policyResp || {};

const digitsOnly = (value) => String(value || '').replace(/[^0-9]/g, '');

let participants = [];
if (Array.isArray(membersResp)) {
  participants = membersResp;
} else if (Array.isArray(membersResp.participants)) {
  participants = membersResp.participants;
} else if (Array.isArray(membersResp.data)) {
  participants = membersResp.data;
} else if (Array.isArray(membersResp.data?.participants)) {
  participants = membersResp.data.participants;
}

const senderPhone = digitsOnly(ev.senderPhone);
const senderJid = ev.senderJid || '';

const sender = participants.find((p) => {
  const candidateId = p?.id || p?.jid || p?.participant || '';
  const candidatePhone = digitsOnly(candidateId);

  return (
    (senderPhone && candidatePhone === senderPhone) ||
    (senderJid && candidateId === senderJid)
  );
});

const senderAdmin = !!(
  sender &&
  (
    sender.admin === true ||
    sender.admin === 'admin' ||
    sender.admin === 'superadmin' ||
    sender.isAdmin === true ||
    sender.isAdmin === 'admin' ||
    sender.isAdmin === 'superadmin'
  )
);

const policy = policyResp.policy || {};

const whitelistRaw = Array.isArray(policyResp.whitelist) ? policyResp.whitelist : [];
const whitelist = whitelistRaw.map((v) => digitsOnly(v)).filter(Boolean);

const senderWhitelisted = senderPhone ? whitelist.includes(senderPhone) : false;

if (!senderAdmin && !senderWhitelisted) {
  return [
    {
      json: {
        ...ev,
        participantsCount: participants.length,
        senderLookup: {
          senderPhone,
          senderJid,
          senderFound: !!sender,
          senderMatchedId: sender?.id || sender?.jid || sender?.participant || null
        },
        senderAdmin,
        senderWhitelisted,
        whitelist,
        policy,
        score: 999,
        reasons: ['non_admin_blocked'],
        shouldModerate: true,
        shouldDelete: true,
        shouldRemove: false
      }
    }
  ];
}

return [
  {
    json: {
      ...ev,
      participantsCount: participants.length,
      senderLookup: {
        senderPhone,
        senderJid,
        senderFound: !!sender,
        senderMatchedId: sender?.id || sender?.jid || sender?.participant || null
      },
      senderAdmin,
      senderWhitelisted,
      whitelist,
      policy,
      score: 0,
      reasons: senderAdmin ? ['sender_admin_allowed'] : ['sender_whitelisted_allowed'],
      shouldModerate: false,
      shouldDelete: false,
      shouldRemove: false
    }
  }
];

const ev = $json;
const changed = ev.participantsChanged || [];
return changed.map(participant => {
  const phone = String(participant).replace(/[^0-9]/g, '');
  return {
    json: {
      groupJid: ev.groupJid,
      participantJid: participant,
      phone,
      action: ev.participantAction || 'unknown',
      seenAt: ev.receivedAt,
    }
  };
});

const root = $json;

// tenta descobrir onde está a lista real de grupos
let groups = [];

if (Array.isArray(root)) {
  groups = root;
} else if (Array.isArray(root.data)) {
  groups = root.data;
} else if (Array.isArray(root.groups)) {
  groups = root.groups;
} else if (Array.isArray(root.data?.groups)) {
  groups = root.data.groups;
} else {
  groups = [];
}

const out = [];

for (const group of groups) {
  if (!group || typeof group !== 'object') {
    continue;
  }

  const participants = Array.isArray(group.participants) ? group.participants : [];
  const groupJid = group.id || group.jid || group.groupJid || null;
  const groupName = group.subject || group.name || '';
  const announce = !!group.announce;
  const restrict = !!group.restrict;

  if (!participants.length) {
    out.push({
      json: {
        groupJid,
        groupName,
        announce,
        restrict,
        participantJid: null,
        phone: null,
        isAdmin: false,
        isPresent: true,
        source: 'initial-sync'
      }
    });
    continue;
  }

  for (const p of participants) {
    if (!p || typeof p !== 'object') {
      continue;
    }

    const participantJid = p.id || p.jid || p.participant || null;
    const adminFlag = p.admin === 'admin' || p.admin === 'superadmin' || p.admin === true;

    out.push({
      json: {
        groupJid,
        groupName,
        announce,
        restrict,
        participantJid,
        phone: String(participantJid || '').replace(/[^0-9]/g, ''),
        isAdmin: adminFlag,
        isPresent: true,
        source: 'initial-sync'
      }
    });
  }
}

return out;

return items.map(item => {
  const row = item.json;
  const groupCount = Number(row.group_count || 0);
  const recentJoins = Number(row.recent_joins_24h || 0);
  const incidents = Number(row.incidents_7d || 0);
  const removals = Number(row.removals_30d || 0);
  const deletions = Number(row.deletions_7d || 0);

  let score =
    (groupCount * 10) +
    (recentJoins * 8) +
    (incidents * 15) +
    (removals * 20) +
    (deletions * 8);

  if (groupCount >= 3) score += 15;
  if (groupCount >= 5) score += 15;
  if (recentJoins >= 3) score += 10;

  score = Math.min(100, Math.max(0, score));

  let riskLevel = 'low';
  if (score >= 70) riskLevel = 'critical';
  else if (score >= 50) riskLevel = 'high';
  else if (score >= 30) riskLevel = 'medium';

  const reasons = [];
  if (groupCount >= 3) reasons.push('multi_group_presence');
  if (recentJoins >= 3) reasons.push('burst_join_pattern');
  if (incidents > 0) reasons.push('message_incidents');
  if (removals > 0) reasons.push('prior_removals');

  return {
    json: {
      phone: row.phone,
      score,
      riskLevel,
      reasonSummary: reasons,
      metrics: {
        groupCount,
        recentJoins,
        incidents,
        removals,
        deletions,
      }
    }
  };
});
